#include "Nexiora/Reasoning/NxConversationalContext.h"
#include <stdio.h>
#include <string.h>
int main(int argc,char**argv){if(argc<2){fprintf(stderr,"Usage: nexiora_dialogue create <session> <evidence> <subject> | ask <session> <question>\n");return 2;}if(strcmp(argv[1],"create")==0&&argc==5){NxCcStatus s=NxConversationalContext_Create(argv[2],argv[3],argv[4]);printf("status=%s\nsession=%s\n",NxConversationalContext_StatusName(s),argv[2]);return s==NX_CC_OK?0:1;}if(strcmp(argv[1],"ask")==0&&argc==4){NxCcTurnResult r;NxCcStatus s=NxConversationalContext_Ask(argv[2],argv[3],&r);printf("status=%s\nturn=%u\nactive_subject=%s\nresolved_question=%s\nreasoning_status=%s\nconfidence=%u\nanswer=%s\nexplanation=%s\nlimitations=%s\n",NxConversationalContext_StatusName(s),r.turn_index,r.active_subject,r.resolved_question,NxGroundedReasoning_StatusName(r.grounded.status),r.grounded.confidence,r.grounded.answer,r.grounded.explanation,r.grounded.limitations);return s==NX_CC_OK?0:1;}fprintf(stderr,"Invalid arguments.\n");return 2;}
